use std::error::Error;
use std::fmt;

struct BuildTarget(String);
impl fmt::Display for BuildTarget {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "{0}", self.0)
    }
}
impl Clone for BuildTarget {
    fn clone(&self) -> Self {
        BuildTarget(self.0.clone())
    }
}

fn simulate_build<T: std::fmt::Display>(target: T) -> Result<(), Box<dyn Error>> {
    println!("Starting build simulation for target: {}", target);
    if target.to_string().contains("windows") || target.to_string().contains("linux") {
        println!("Successfully compiled artifact for {}", target);
        Ok(())
    } else {
        Err(format!("Unsupported build target: {}", target).into())}
}

fn main() -> Result<(), Box<dyn Error>> {
    let targets = vec![
        BuildTarget("linux-x64".to_string()),
        BuildTarget("windows-msvc".to_string()),
        BuildTarget("macos-arm64".to_string()),
    ];

    for target in targets {
        match simulate_build(target.clone()) {
            Ok(_) => println!("Finished build for {}", target),
            Err(e) => eprintln!("Failed to build for {}: {}", target, e),
        }
    }

    Ok(())
}

