use std::collections::BTreeMap;

struct DatabaseIndex {
    index: BTreeMap<u64, String>,
}

impl DatabaseIndex {
    fn new() -> Self {
        DatabaseIndex { index: BTreeMap::new() }
    }

    fn insert(&mut self, key: u64, value: &str) {
        self.index.insert(key, value.to_string());
    }

    fn get(&self, key: u64) -> Option<&str> {
        self.index.get(&key).map(|s| s.as_str())
    }

    fn count(&self) -> usize {
        self.index.len()
    }
}

fn main() {
    let mut index = DatabaseIndex::new();
    index.insert(100, "User data for first entry");
    index.insert(50, "System configuration record");
    index.insert(200, "Large payload backup");

    match index.get(50) {
        Some(data) => println!("Found data for key 50: {}", data),
        None => println!("Key 50 not found.")
    }

    println!("Total records indexed: {}", index.count());
}

